mapper.select:
SELECT COUNT(1) FROM r_user_ssh_sessions S LEFT JOIN R_USER_T U ON S.USER_ID = U.USER_ID WHERE 1=1
AND S.USER_ID = #{filterUserId}
AND (U.NAME LIKE CONCAT('%', #{search}, '%') OR S.HOST LIKE CONCAT('%', #{search}, '%') OR S.SSH_USER LIKE CONCAT('%', #{search}, '%') OR S.REMOTE_ADDR LIKE CONCAT('%', #{search}, '%'))

SELECT C.CMMANDS_ID AS commandsId, C.SESSION_ID AS sessionId, C.COMMAND AS command, C.EXECUTED_AT AS executedAt FROM r_user_ssh_commands C INNER JOIN r_user_ssh_sessions S ON C.SESSION_ID = S.SESSION_ID WHERE C.SESSION_ID = #{sessionId}
AND S.USER_ID = #{filterUserId}
ORDER BY C.EXECUTED_AT ASC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM r_user_ssh_commands C
INNER JOIN r_user_ssh_sessions S ON C.SESSION_ID = S.SESSION_ID
WHERE C.SESSION_ID = #{sessionId}

    AND S.USER_ID = #{filterUserId}

SELECT FL.LOG_ID AS logId, FL.SESSION_ID AS sessionId, FL.USER_ID AS userId, U.NAME AS userName, FL.OPERATION AS operation, FL.FILE_PATH AS filePath, FL.FILE_SIZE AS fileSize, FL.EXECUTED_AT AS executedAt FROM r_user_sftp_logs FL LEFT JOIN R_USER_T U ON FL.USER_ID = U.USER_ID INNER JOIN r_user_ssh_sessions SS ON FL.SESSION_ID = SS.SESSION_ID WHERE FL.SESSION_ID = #{sessionId}
AND SS.USER_ID = #{filterUserId}
ORDER BY FL.EXECUTED_AT ASC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM r_user_sftp_logs FL
INNER JOIN r_user_ssh_sessions SS ON FL.SESSION_ID = SS.SESSION_ID
WHERE FL.SESSION_ID = #{sessionId}

    AND SS.USER_ID = #{filterUserId}
